// Extract message from Telegram update
const update = $input.first().json.body;
const message = update.message || {};
const text = (message.text || '').toLowerCase().trim();
const chatId = message.chat?.id?.toString();
const userId = message.from?.id?.toString();

return [{ json: { text, chat_id: chatId, user_id: userId, raw_text: message.text || '' } }];

// Intent Recognition — updated for 90-Day War Plan
const text = $input.first().json.text;
const raw = $input.first().json.raw_text;
let intent = 'unknown';
let task = null;
let meta = {};

// Specific task done
const specificMatch = text.match(/^(prayer|bible|book|code|career)\s+done$/);

if (specificMatch) {
  intent = 'mark_done_specific';
  task = specificMatch[1];
}
else if (text.includes('done') || text === '\u2705') intent = 'mark_done_generic';
else if (text.includes('reschedule') || text.includes('move')) intent = 'reschedule';
else if (text.includes('pep talk')) intent = 'pep_talk';
else if (text.includes('stats') || text.includes('how am i doing')) intent = 'stats';
else if (text.includes('skip today')) intent = 'skip_day';
else if (text.includes('pause')) intent = 'pause';
else if (text.includes('career done')) { intent = 'mark_done_specific'; task = 'career'; }

// Revenue-related intents
else if (text.includes('revenue')) { intent = 'revenue'; }
else if (text.match(/sent\s+(\d+)\s+proposals?/)) {
  intent = 'sent_proposals';
  meta.proposals_count = parseInt(text.match(/sent\s+(\d+)\s+proposals?/)[1]);
}
else if (text.match(/earned\s+\$?(\d+)/)) {
  intent = 'earned_revenue';
  meta.amount = parseInt(text.match(/earned\s+\$?(\d+)/)[1]);
}
else if (text.match(/published\s+(\d+)\s+videos?/)) {
  intent = 'published_videos';
  meta.video_count = parseInt(text.match(/published\s+(\d+)\s+videos?/)[1]);
}

return [{ json: { ...$input.first().json, intent, task, meta } }];

// Day Counter — weekday-based 90-day counter starting March 2, 2026
function getWeekdayDates() {
  const dates = [];
  const d = new Date('2026-03-02T00:00:00+01:00');
  while (dates.length < 90) {
    if (d.getDay() !== 0 && d.getDay() !== 6) dates.push(new Date(d));
    d.setDate(d.getDate() + 1);
  }
  return dates;
}
const weekdays = getWeekdayDates();
const now = new Date();
const todayStr = now.toISOString().split('T')[0];
let dayNum = null;
for (let i = 0; i < weekdays.length; i++) {
  if (weekdays[i].toISOString().split('T')[0] === todayStr) { dayNum = i + 1; break; }
}
const isWeekend = now.getDay() === 0 || now.getDay() === 6;
const weekNum = dayNum ? Math.ceil(dayNum / 5) : null;
return [{ json: { ...$input.first().json, day_number: dayNum, week_num: weekNum, is_weekend: isWeekend, date: todayStr } }];

// Action Handler — processes ALL intents and generates patch_body, reply_text, needs_ai
const intent = $('Intent Recognition').first().json;
const dayNum = $('Day Counter').first().json.day_number;
const dailyLog = $('Get Daily Log').first().json;
const logData = Array.isArray(dailyLog) && dailyLog[0] ? dailyLog[0] : {};
const task = intent.task;
const meta = intent.meta || {};

const TASK_MAP = {
  'prayer': { field: 'prayer_s1', value: true, reply: 'Prayer session marked done.' },
  'bible': { field: 'nt_chapters_read', value: '["completed"]', reply: 'NT reading marked done.' },
  'book': { field: 'book_pages', value: 50, reply: 'Book reading logged — 50 pages.' },
  'code': { field: 'code_hrs', value: 1.2, reply: 'Coding block logged — 1.2 hrs.' },
  'career': { field: 'career_done', value: true, reply: 'Career tasks marked done.' }
};

let patchBody = {};
let replyText = '';
let needsAi = false;
let needsPatch = false;

switch (intent.intent) {
  case 'mark_done_specific':
    if (task && TASK_MAP[task]) {
      const mapping = TASK_MAP[task];
      patchBody[mapping.field] = mapping.value;
      replyText = mapping.reply;
    } else {
      replyText = 'Task marked done.';
    }
    break;

  case 'mark_done_generic':
    replyText = 'Noted! Task marked as done.';
    break;

  case 'sent_proposals':
    patchBody.proposals_sent = meta.proposals_count || 0;
    replyText = `Logged ${meta.proposals_count || 0} proposals sent.`;
    break;

  case 'earned_revenue':
    patchBody.revenue_today = meta.amount || 0;
    replyText = `Logged $${meta.amount || 0} revenue. Keep stacking.`;
    break;

  case 'published_videos':
    patchBody.videos_published = meta.video_count || 0;
    replyText = `Logged ${meta.video_count || 0} videos published.`;
    break;

  case 'pep_talk':
    needsAi = true;
    replyText = ''; // Will be filled by AI
    break;

  case 'stats': {
    const codeHrs = logData.code_hrs || 0;
    const prayer1 = logData.prayer_s1 ? 'Done' : 'Pending';
    const prayer2 = logData.prayer_s2 ? 'Done' : 'Pending';
    const ntReading = logData.nt_chapters_read ? 'Done' : 'Pending';
    const bookPages = logData.book_pages || 0;
    const careerDone = logData.career_done ? 'Done' : 'Pending';
    const proposals = logData.proposals_sent || 0;
    const revenue = logData.revenue_today || 0;
    replyText = `*Day ${dayNum} Stats:*\n` +
      `- Prayer S1: ${prayer1}\n` +
      `- Prayer S2: ${prayer2}\n` +
      `- NT Reading: ${ntReading}\n` +
      `- Book Pages: ${bookPages}\n` +
      `- Code Hours: ${codeHrs} / 3.5 target\n` +
      `- Career: ${careerDone}\n` +
      `- Proposals Sent: ${proposals}\n` +
      `- Revenue Today: $${revenue}`;
    break;
  }

  case 'pause':
    replyText = 'System paused. Send "resume" to reactivate.';
    break;

  case 'skip_day':
    replyText = 'Day noted as skipped. Rest if you must, but come back stronger.';
    break;

  case 'revenue':
    const rev = logData.revenue_today || 0;
    const prop = logData.proposals_sent || 0;
    replyText = `*Revenue Summary — Day ${dayNum}:*\nRevenue today: $${rev}\nProposals sent: ${prop}`;
    break;

  default:
    replyText = 'I didn\'t catch that. Try: done, stats, pep talk, revenue, pause, or skip today.';
    break;
}

needsPatch = Object.keys(patchBody).length > 0;

return [{ json: {
  day_num: dayNum,
  patch_body: patchBody,
  reply_text: replyText,
  needs_patch: needsPatch,
  needs_ai: needsAi,
  intent: intent.intent
} }];

